import React from 'react';

interface PatientCardProps {
  patient: any;
  onEdit: () => void;
  onDelete: () => void;
}

const PatientCard = ({ patient, onEdit, onDelete }: PatientCardProps) => (
  <div className="bg-white p-6 rounded-3xl border-l-8 border-[#0D9488] shadow-sm hover:shadow-md transition-all group relative">
    <div className="flex gap-4">
      <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-2xl group-hover:scale-110 transition-transform">
        👤
      </div>
      <div>
        <div className="flex items-center gap-3 mb-1">
          <h4 className="text-xl font-bold text-slate-800">{patient.first_name} {patient.last_name}</h4>
          <span className="bg-teal-50 text-[#0D9488] text-[10px] px-2.5 py-1 rounded-full font-bold uppercase border border-teal-100">
            {patient.gender}
          </span>
        </div>
        <p className="text-[#0D9488] font-medium text-sm">{patient.email}</p>
        <p className="text-slate-400 text-xs mt-2 font-mono">{patient.contact_number}</p>
      </div>
    </div>
    <div className="absolute top-4 right-4 flex gap-3 opacity-0 group-hover:opacity-100 transition-opacity">
      <button onClick={onEdit} className="text-slate-400 hover:text-teal-600 font-bold text-xs">EDIT</button>
      <button onClick={onDelete} className="text-slate-400 hover:text-red-500 font-bold text-xs">DELETE</button>
    </div>
  </div>
);

export default PatientCard;
